B.PJ=new A.i3("txek","Txek","https://www.txek.fr/txek-faq/",null,B.o_,!1,B.Q7)
B.a5D=new A.ie("Pr\xe9sentation","Ligretto est un jeu de cartes rapide et amusant qui plaira \xe0 tous ceux et toutes celles qui aiment l'animation.")
B.a5I=new A.ie("Joueurs","De 2 \xe0 4 joueurs \xe0 partir de 8 ans avec une seule bo\xeete. Jusqu'\xe0 8 joueurs avec deux bo\xeetes diff\xe9rentes, ou 12 joueurs avec la bo\xeete bleue, verte et rouge.")
B.a5E=new A.ie("Mat\xe9riel","4 jeux de 40 cartes, dont le dos porte une couleur et un motif diff\xe9rent (bille, pyramide, d\xe9, cristaux). La face avant comprend des valeurs de 1 \xe0 10 en 4 couleurs.")
B.a5J=new A.ie("But du jeu","Poser au milieu autant de cartes de la m\xeame couleur que possible, en ordre croissant (de 1 \xe0 10), et \xeatre le premier \xe0 \xe9liminer tout son Ligretto.")
B.a5H=new A.ie("Pr\xe9paration","Chaque joueur re\xe7oit un jeu de 40 cartes (m\xeame motif) qu'il m\xe9lange, motif vers le haut. Il constitue ensuite :\n\n\u2022 Le Ligretto : il tire 10 cartes, \xe0 l'envers, et les empile devant lui, chiffres vers le haut.\n\u2022 La s\xe9rie : il tire 3 autres cartes et les pose c\xf4te \xe0 c\xf4te \xe0 droite du Ligretto, chiffres vers le haut (5 cartes \xe0 deux joueurs, 4 cartes \xe0 trois joueurs).\n\u2022 La main : il garde le reste des cartes dans la main, motif vers le haut.")
B.a5F=new A.ie("D\xe9roulement de la partie","Un joueur donne le signal du d\xe9part : \xab Ligretto ! \xbb Tous les joueurs qui ont un 1 le posent aussit\xf4t au milieu. Tout le monde joue en m\xeame temps et pose, s'il le peut, des cartes au milieu, en se servant des cartes du Ligretto, de la s\xe9rie ou de la main.\n\nSi un joueur n'a pas de 1 sur son Ligretto ou dans sa s\xe9rie, il tire rapidement 3 cartes de sa main, \xe0 l'envers, et les empile chiffres vers le haut, jusqu'\xe0 en trouver un.\n\nD\xe8s qu'un 1 est pos\xe9, chaque joueur essaie d'empiler un 2, puis un 3, etc. de la m\xeame couleur sur ce 1 ou un autre 1 d\xe9pos\xe9 par un autre joueur. Une fois arriv\xe9e \xe0 10, la pile est compl\xe8te.\n\nChaque joueur tire r\xe9guli\xe8rement trois cartes de sa main et les empile devant lui, chiffres vers le haut, de mani\xe8re \xe0 ne voir que la premi\xe8re carte, qu'il pose au milieu d\xe8s qu'il le peut. Quand la main est \xe9puis\xe9e, on reprend la pile retourn\xe9e et on recommence \xe0 tirer les cartes 3 par 3.")
B.a5K=new A.ie("Fin de partie et gagnant","Le premier joueur qui a vid\xe9 son Ligretto annonce \xab Ligretto stop \xbb. La partie est termin\xe9e : plus aucune carte ne peut \xeatre pos\xe9e.")
B.a5G=new A.ie("Comptage des points","Les joueurs trient les cartes du milieu par motif. Chaque joueur compte les cartes pr\xe9sentant son motif :\n\n\u2022 Chaque carte pos\xe9e au milieu compte 1 point positif (quel que soit son chiffre).\n\u2022 Chaque carte restant dans le Ligretto compte 2 points n\xe9gatifs.\n\u2022 Les cartes restant dans la s\xe9rie ou dans la main ne sont pas compt\xe9es.\n\nLe premier joueur qui atteint 99 points positifs a gagn\xe9. Si plus personne ne peut jouer parce que toutes les cartes utiles sont d\xe9j\xe0 sur les piles de Ligretto, le joueur qui m\xe8ne \xe0 ce moment-l\xe0 gagne la partie.")
B.a5L=new A.ie("R\xe8gles avanc\xe9es","Chaque joueur peut aussi tirer des cartes du Ligretto et de la main pour les d\xe9poser dans la s\xe9rie, mais seulement en ordre d\xe9croissant (par exemple un 8 sur un 9) et avec des couleurs diff\xe9rentes de la carte du dessous. Attention \xe0 ne pas trop garnir la s\xe9rie, au risque de d\xe9pouiller son Ligretto.")
B.WT=s([B.a5D,B.a5I,B.a5E,B.a5J,B.a5H,B.a5F,B.a5K,B.a5G,B.a5L],t.sl)
